      Variables: []rewrite.APITemplateVariable{
        {Name: "first_name", Fallback: &firstNameFallback},
        {Name: "order_id", Fallback: &orderIDFallback},
      },
    },
  })
  if err != nil { log.Fatal(err) }
}

